def slugify(value: str) -> str:
    normalized = value.lower().replace("+", " plus ")
    return re.sub(r"[^a-z0-9]+", "-", normalized).strip("-")


def clean(value: Any) -> str:
    return str(value or "").strip()


def numbers(value: Any) -> list[float]:
    found = re.findall(r"-?\d+(?:[.,]\d+)?", clean(value))
    return [float(item.replace(",", ".")) for item in found]


def midpoint(value: Any) -> float | None:
    text = clean(value).lower()
    if "base polymer" in text or "follow base" in text:
        return None
    values = numbers(value)
    if not values:
        return None
    if len(values) == 1:
        return values[0]
    return sum(values[:2]) / 2


def modulus_midpoint(value: Any) -> float | None:
    result = midpoint(value)
    if result is not None and "mpa" in clean(value).lower():
        return result / 1000
    return result


def maximum(value: Any) -> float | None:
    values = numbers(value)
    return max(values) if values else None


def clamp(value: float, low: float = 0, high: float = 10) -> float:
    return max(low, min(high, value))


def score_between(value: float | None, low: float, high: float, floor: float = 1) -> int:
    if value is None:
        return int(floor)
    if high == low:
        return int(floor)
    return round(clamp(floor + (value - low) / (high - low) * (10 - floor)))


def text_has(value: str, *needles: str) -> bool:
    text = value.lower()
    return any(needle in text for needle in needles)


def text_tokens(value: str) -> set[str]:
    return set(re.findall(r"[a-z0-9]+", value.lower()))


def token_has(tokens: set[str], *needles: str) -> bool:
    return any(needle in tokens for needle in needles)


def boolish(value: str) -> bool:
    text = value.lower()
    return not text_has(text, " no", "not ", "avoid", "unsupported", "not recommended") and text_has(
        text,
        "yes",
        "usually yes",
        "compatible",
        "direct",
        "works",
    )


def family_color(record: dict[str, str]) -> str:
    haystack = f"{record.get('Material', '')} {record.get('Family', '')} {record.get('Full name', '')}".lower()
    if text_has(haystack, "pla", "polylactic"):
        return "#9b5de5"
    if text_has(haystack, "pet", "copolyester", "cpe", "pctg", "pbt"):
        return "#00b4d8"
    if text_has(haystack, "abs", "asa", "hips", "styrenic", "san"):
        return "#ef476f"
    if text_has(haystack, "tpu", "tpe", "tpc", "tpv", "elastomer", "flex"):
        return "#f59e0b"
    if text_has(haystack, "polyamide", "nylon", "pa6", "pa11", "pa12", "pa66", "ppa", "paht", "copa"):
        return "#06a77d"
    if text_has(haystack, "polycarbonate", "pc"):
        return "#4361ee"
    if text_has(haystack, "peek", "pekk", "pei", "pps", "psu", "ppsu", "pesu", "lcp", "high-temperature"):
        return "#d63384"
    if text_has(haystack, "support", "pva", "bvoh", "breakaway"):
        return "#64748b"
    if text_has(haystack, "pp", "polypropylene", "hdpe", "ldpe", "polyolefin"):
        return "#43aa8b"
    return "#64748b"


def subfamily(record: dict[str, str]) -> str:
    name = record.get("Material", "")
    family = record.get("Family", "")
    kind = record.get("Record kind", "")
    haystack = f"{name} {family} {kind}".lower()
    if "modifier" in kind.lower() or "taxonomy" in kind.lower():
        return "Modifier taxonomy"
    if text_has(haystack, "carbon", " cf"):
        return "Carbon fibre"
    if text_has(haystack, "glass", " gf"):
        return "Glass fibre"
    if text_has(haystack, "support", "pva", "bvoh", "breakaway"):
        return "Support"
    if text_has(haystack, "esd", "conductive"):
        return "ESD / conductive"
    if text_has(haystack, "fr", "flame"):
        return "Flame-retardant"
    if text_has(haystack, "filled", "wood", "metal", "stone", "ceramic", "glow"):
        return "Filled / decorative"
    return "Approximate catalog"


def category_filter_keys(record: dict[str, str]) -> list[str]:
    name = record.get("Material", "")
    family = record.get("Family", "")
    sub = subfamily(record)
    kind = record.get("Record kind", "")
    haystack = f"{name} {family} {sub} {kind} {record.get('Aliases', '')}".lower()
    tokens = text_tokens(haystack)
    keys: list[str] = ["catalog-backlog"]
    is_pla = token_has(tokens, "pla") or text_has(haystack, "polylactic")
    if is_pla:
        keys.append("group-pla")
    if token_has(tokens, "pet", "petg", "pett", "copet", "cpe", "pctg", "pbt") or text_has(haystack, "copolyester") or (text_has(haystack, "polyester") and not is_pla):
        keys.append("group-polyester")
    if token_has(tokens, "abs", "asa", "hips", "san") or text_has(haystack, "styrenic"):
        keys.append("group-styrenic")
    if token_has(tokens, "tpu", "tpe", "tpc", "tpv") or text_has(haystack, "elastomer", "flexible"):
        keys.append("group-elastomer")
    if token_has(tokens, "pa6", "pa11", "pa12", "pa66", "ppa", "paht", "copa") or text_has(haystack, "polyamide", "nylon"):
        keys.append("group-polyamide")
    if token_has(tokens, "pc") or text_has(haystack, "polycarbonate"):
        keys.append("group-pc")
    if token_has(tokens, "peek", "pekk", "pei", "pps", "psu", "ppsu", "pesu", "lcp", "paek"):
        keys.append("group-high-temp")
    if token_has(tokens, "pva", "bvoh") or text_has(haystack, "support", "breakaway"):
        keys.append("group-support")
    if token_has(tokens, "cf", "gf", "carbon", "glass", "kevlar", "aramid", "basalt", "filled", "wood", "metal", "ceramic", "mineral", "stone", "glow"):
        keys.append("group-filled")
    if token_has(tokens, "esd") or text_has(haystack, "conductive"):
        keys.append("group-esd")
    if token_has(tokens, "pp", "hdpe", "ldpe") or text_has(haystack, "polypropylene", "polyolefin"):
        keys.append("group-polyolefin")
    return sorted(set(keys))


def score_profile(record: dict[str, str]) -> dict[str, dict[str, int]]:
    name = record.get("Material", "")
    family = record.get("Family", "")
    notes = record.get("Notes", "")
    best_for = record.get("Best for", "")
    avoid_for = record.get("Avoid for", "")
    haystack = f"{name} {family} {notes} {best_for} {avoid_for}".lower()
    hdt = midpoint(record.get("HDT")) or midpoint(record.get("Continuous service temp"))
    continuous = midpoint(record.get("Continuous service temp"))
    tensile = midpoint(record.get("Tensile strength"))
    modulus = modulus_midpoint(record.get("Tensile modulus"))
    nozzle_max = maximum(record.get("Nozzle temp"))
    bed_max = maximum(record.get("Bed temp"))
    hardened = boolish(record.get("Hardened nozzle"))
    chamber = record.get("Chamber/enclosure", "")
    enclosure = text_has(chamber, "enclosure", "chamber", "heated") and not text_has(
        chamber, "not needed", "ambient normally", "ambient; enclosure not needed"
    )

    rigidity = score_between(modulus, 0.4, 10)
    strength = score_between(tensile, 20, 170)
    heat = score_between(hdt or continuous, 50, 230)

    impact = 5
    if text_has(haystack, "tpu", "tpe", "elastomer", "flexible", "damping"):
        impact = 9
    elif text_has(haystack, "pc", "polycarbonate", "nylon", "polyamide", "pa6", "pa11", "pa12", "abs"):
        impact = 7
    elif text_has(haystack, "petg", "copolyester", "asa"):
        impact = 6
    elif text_has(haystack, "pla", "ceramic", "stone", "metal"):
        impact = 3
    if text_has(haystack, "carbon", "glass", "basalt", "ceramic", "mineral", "filled"):
        impact -= 2

    layer = 5
    if text_has(haystack, "petg", "copolyester", "tpu", "tpe", "nylon", "polyamide"):
        layer = 7
    if text_has(haystack, "carbon", "glass", "filled", "peek", "pekk", "pps", "pei"):
        layer -= 2

    chemical = 5
    if text_has(haystack, "pvdf", "pps", "peek", "pekk", "pei", "pp", "polypropylene", "pom", "pet", "pctg", "chemical"):
        chemical = 8
    elif text_has(haystack, "pla"):
        chemical = 3

    water = 6
    if text_has(haystack, "pp", "polypropylene", "petg", "pet", "asa", "abs", "pvdf", "pps", "peek", "pekk"):
        water = 8
    if text_has(haystack, "pva", "bvoh", "water-soluble"):
        water = 0
    elif text_has(haystack, "nylon", "polyamide", "pa6", "pa11", "pa12", "pa66", "ppa", "paht"):
        water = 5

    moisture_sensitivity = 4
    if text_has(haystack, "pva", "bvoh", "nylon", "polyamide", "pa6", "pa11", "pa12", "pa66", "ppa", "paht"):
        moisture_sensitivity = 9
    elif text_has(haystack, "tpu", "tpe", "pc", "pet", "petg", "copolyester", "peek", "pekk", "pps", "pei"):
        moisture_sensitivity = 6
    elif text_has(haystack, "pla", "abs", "asa", "pp"):
        moisture_sensitivity = 3

    printability = 8
    if nozzle_max and nozzle_max > 300:
        printability -= 4
    elif nozzle_max and nozzle_max > 280:
        printability -= 2
    if bed_max and bed_max > 100:
        printability -= 1
    if enclosure:
        printability -= 2
    if hardened:
        printability -= 1
    if text_has(haystack, "flexible", "tpu", "tpe"):
        printability -= 2
    if text_has(haystack, "support", "pva", "bvoh"):
        printability -= 2

    creep = score_between((hdt or 50) + (modulus or 1) * 8, 50, 260)
    uv = 4
    if text_has(haystack, "asa", "pvdf", "uv", "weather"):
        uv = 9
    elif text_has(haystack, "petg", "pet", "pp", "pc"):
        uv = 5
    elif text_has(haystack, "pla", "abs", "nylon"):
        uv = 3

    price = 3
    if text_has(haystack, "cf", "carbon", "gf", "glass", "kevlar", "aramid", "esd", "conductive", "fr"):
        price += 2
    if text_has(haystack, "peek", "pekk", "pei", "pps", "ppsu", "pesu", "lcp", "ppa", "paht"):
        price += 4
    if text_has(haystack, "pla", "petg", "abs") and price < 5:
        price = 2

    dry = {
        "rigidity_xy": rigidity,
        "strength_xy": strength,
        "rigidity_z": clamp(round(rigidity * 0.65 + layer * 0.25)),
        "layer_adhesion": layer,
        "impact_resistance": clamp(round(impact)),
        "heat_resistance": heat,
        "chemical_resistance": chemical,
        "water_resistance": water,
        "moisture_tolerance": clamp(10 - moisture_sensitivity),
        "printability": clamp(round(printability)),
        "creep_resistance": creep,
        "uv_resistance": uv,
        "price_range": clamp(price),
    }
    dry = {key: int(clamp(value)) for key, value in dry.items()}
    penalty = moisture_sensitivity / 10
    wet = dry.copy()
    for key, amount in (("strength_xy", 2.0), ("rigidity_xy", 1.2), ("layer_adhesion", 1.8), ("printability", 1.5), ("heat_resistance", 0.9)):
        wet[key] = int(clamp(round(wet[key] - amount * penalty)))
    return {"dry": dry, "wet": wet}


def real_property(label: str, unit: str = "", value: float | None = None) -> dict[str, Any]:
    value = midpoint(label) if value is None else value
    clean_label = clean(label)
    return {"value": value, "label": clean_label, "unit": unit}


def compatibility(record: dict[str, str], printers: Iterable[Any] | None = None) -> dict[str, Any]:
    direct = boolish(record.get("Direct path compatible", ""))
    aux = boolish(record.get("Aux path compatible", ""))
    ams = boolish(record.get("AMS compatible", ""))
    hardened = boolish(record.get("Hardened nozzle", ""))
    nozzle_max = maximum(record.get("Nozzle temp"))
    bed_max = maximum(record.get("Bed temp"))
    chamber_text = record.get("Chamber/enclosure", "")
    chamber_max = maximum(chamber_text)
    requires_enclosure = text_has(chamber_text, "enclosure", "chamber", "heated") and not text_has(
        chamber_text, "not needed", "ambient normally", "ambient; enclosure not needed"
    )

    filter_keys = []
    if ams:
        filter_keys.append("ams-compatible")
    if hardened:
        filter_keys.append("hardened-nozzle")

    status_labels = {
        "recommended": "Recommended",
        "precautions": "Compatible with precautions",
        "needs_confirmation": "Needs hardware confirmation",
        "not_recommended": "Not recommended",
    }
    status_rank = {"recommended": 5, "precautions": 4, "needs_confirmation": 3, "not_recommended": 2}
    printer_results: list[dict[str, Any]] = []
    compatible_filter_keys: list[str] = []

    def active_tools(printer: Any) -> list[Any]:
        tools = [tool for tool in getattr(printer, "tools", []) if getattr(tool, "is_active", True)]
        return sorted(tools, key=lambda item: (getattr(item, "tool_order", 1), getattr(item, "id", 0)))

    def installed_nozzle(printer: Any, tool: Any | None) -> Any | None:
        nozzles = [nozzle for nozzle in getattr(printer, "nozzles", []) if getattr(nozzle, "installed", False) and getattr(nozzle, "is_active", True)]
        if tool is not None:
            nozzles = [nozzle for nozzle in nozzles if getattr(nozzle, "tool_id", None) == getattr(tool, "id", None)]
        return nozzles[0] if nozzles else None

    def nozzle_bool(nozzle: Any, key: str) -> bool | None:
        value = getattr(nozzle, key, None)
        if value is not None:
            return value
        catalog = getattr(nozzle, "catalog_item", None)
        if catalog is not None:
            value = getattr(catalog, key, None)
            if value is not None:
                return value
        text = f"{getattr(nozzle, 'label', '')} {getattr(nozzle, 'nozzle_material', '')} {getattr(nozzle, 'brand_product', '')}".lower()
        if text_has(text, "hardened", "ruby", "tungsten", "carbide", "abrasive"):
            return True
        if text_has(text, "brass", "stainless"):
            return False
        return None

    def nozzle_limit(nozzle: Any) -> float | None:
        value = getattr(nozzle, "max_temp_c", None)
        if value is not None:
            return value
        catalog = getattr(nozzle, "catalog_item", None)
        return getattr(catalog, "max_temp_c", None) if catalog is not None else None

    for printer in printers or []:
        key = f"printer-{getattr(printer, 'slug', '')}"
        tool_results: list[dict[str, Any]] = []
        tools = active_tools(printer) or [None]
        for tool in tools:
            nozzle = installed_nozzle(printer, tool)
            tool_limit = (getattr(tool, "max_hotend_c", None) if tool is not None else None) or getattr(printer, "nozzle_max_c", 0) or 0
            n_limit = nozzle_limit(nozzle) if nozzle is not None else None
            effective = min(tool_limit, n_limit) if tool_limit and n_limit is not None else tool_limit
            blockers: list[str] = []
            confirmations: list[str] = []
            cautions: list[str] = []
            strengths: list[str] = []

            if nozzle is None:
                confirmations.append("No installed nozzle is assigned to this tool.")
            elif n_limit is None:
                confirmations.append("Installed nozzle maximum safe temperature is unknown.")
            if nozzle_max is not None:
                if nozzle is not None and n_limit is not None and effective < nozzle_max:
                    blockers.append(f"Effective nozzle temperature limit is {effective:g} C, below the material guide of {nozzle_max:g} C.")
                elif nozzle is not None and n_limit is not None:
                    strengths.append("Effective nozzle temperature is sufficient.")
                else:
                    confirmations.append("Nozzle temperature compatibility cannot be fully verified.")
            if bed_max is not None and getattr(printer, "bed_max_c", 0) and bed_max > getattr(printer, "bed_max_c", 0):
                blockers.append("Bed temperature is below the material guide.")
            elif bed_max is not None:
                strengths.append("Bed temperature is sufficient.")
            if requires_enclosure and not getattr(printer, "enclosed", False):
                blockers.append("Enclosure is required or strongly recommended, but this printer is open-frame.")
            if chamber_max is not None and chamber_max > 45 and getattr(printer, "chamber_max_c", 0) and chamber_max > getattr(printer, "chamber_max_c", 0):
                blockers.append("Chamber capability is below the material guide.")
            if hardened:
                abrasive = nozzle_bool(nozzle, "abrasive_ready") if nozzle is not None else None
                if abrasive is True:
                    strengths.append("Abrasive-ready nozzle is installed.")
                elif abrasive is False:
                    blockers.append("Material needs an abrasive-ready or hardened nozzle.")
                else:
                    confirmations.append("Abrasive-nozzle suitability is unknown.")
            if getattr(printer, "ams_capable", False) and not ams:
                cautions.append("AMS / automatic feeder is not recommended for this material.")

            if blockers:
                status = "not_recommended"
            elif confirmations:
                status = "needs_confirmation"
            elif cautions:
                status = "precautions"
            else:
                status = "recommended"
            tool_results.append(
                {
                    "tool_id": getattr(tool, "id", None),
                    "tool_name": getattr(tool, "name", "Installed nozzle compatibility") if tool is not None else "Installed nozzle compatibility",
                    "nozzle_id": getattr(nozzle, "id", None) if nozzle is not None else None,
                    "nozzle_label": getattr(nozzle, "label", "No installed nozzle") if nozzle is not None else "No installed nozzle",
                    "status": status,
                    "status_label": status_labels[status],
                    "effective_max_c": effective,
                    "effective_max_confirmed": nozzle is not None and n_limit is not None,
                    "required_nozzle_c": nozzle_max,
                    "blockers": blockers,
                    "confirmations": confirmations,
                    "cautions": cautions,
                    "strengths": strengths,
                    "reasons": strengths + confirmations + cautions + blockers,
                }
            )
        best = max(tool_results, key=lambda item: status_rank[item["status"]])
        status = best["status"]
        if status == "recommended":
            summary = f"Compatible with {getattr(printer, 'name', 'printer')}"
        elif status == "precautions":
            summary = f"Compatible with {getattr(printer, 'name', 'printer')} with limitations"
        elif status == "needs_confirmation":
            summary = f"Needs nozzle confirmation on {getattr(printer, 'name', 'printer')}"
        else:
            summary = f"Not recommended for {getattr(printer, 'name', 'printer')}"
        result = {
            "printer_id": getattr(printer, "id", None),
            "printer_slug": getattr(printer, "slug", ""),
            "printer_name": getattr(printer, "name", "Printer"),
            "status": status,
            "status_label": status_labels[status],
            "summary": summary,
            "filter_key": key,
            "is_compatible_filter_match": status in {"recommended", "precautions"},
            "best_result": best,
            "tool_results": tool_results,
        }
        printer_results.append(result)
        if key != "printer-" and result["is_compatible_filter_match"]:
            compatible_filter_keys.append(key)
            filter_keys.append(key)

    preferred = max(printer_results, key=lambda item: status_rank[item["status"]]) if printer_results else None

    return {
        "direct_path": direct,
        "aux_path": aux,
        "ams": ams,
        "requires_enclosure": requires_enclosure,
        "printer_matches": compatible_filter_keys,
        "printer_match_labels": [item["printer_name"] for item in printer_results if item["is_compatible_filter_match"]],
        "printer_results": printer_results,
        "preferred_printer_result": preferred,
        "summary_label": preferred["summary"] if preferred else "No saved printer selected",
        "compatible_filter_keys": compatible_filter_keys,
        "filter_keys": sorted(set(filter_keys)),
        "nozzle_max_c": nozzle_max,
        "bed_max_c": bed_max,
        "chamber_max_c": maximum(chamber_text),
    }


def catalog_payload(record: dict[str, str], printers: Iterable[Any] | None = None) -> dict[str, Any]:
    name = clean(record.get("Material"))
    slug = slugify(name)
    density = midpoint(record.get("Density")) or 0
    hdt = midpoint(record.get("HDT")) or 0
    continuous = midpoint(record.get("Continuous service temp")) or 0
    scores = score_profile(record)
    hardened = boolish(record.get("Hardened nozzle", ""))
    aliases = clean(record.get("Aliases"))
    source_title = clean(record.get("Source title")) or CATALOG_SOURCE_TITLE
    source_url = clean(record.get("Source URL"))
    notes = clean(record.get("Notes"))
    reference = clean(record.get("Reference / property data"))
    source_notes = " ".join(part for part in (CATALOG_SOURCE_NOTE, reference, notes, source_title, source_url) if part)
    settings = {
        "nozzle": clean(record.get("Nozzle temp")) or "See exact product TDS",
        "bed": clean(record.get("Bed temp")) or "See exact product TDS",
        "chamber": clean(record.get("Chamber/enclosure")) or "See exact product TDS",
        "drying": clean(record.get("Drying")) or "Use exact spool TDS",
        "speed": "Use exact product profile",
        "recommended_nozzle": "Hardened nozzle" if hardened else "Standard nozzle",
        "main_compatible": boolish(record.get("Direct path compatible", "")),
        "aux_compatible": boolish(record.get("Aux path compatible", "")),
        "ams_compatible": boolish(record.get("AMS compatible", "")),
        "cooling": "Use exact product profile",
    }
    props = {
        "density_g_cm3": density,
        "mass_g_mm3": round(density / 1000, 5) if density else 0,
        "hdt_c": hdt,
        "continuous_service_c": continuous,
        "moisture_sensitivity": int(clamp(10 - scores["dry"].get("moisture_tolerance", 5))),
        "water_resistance": scores["dry"].get("water_resistance", 5),
        "flame_resistance": 6 if text_has(f"{name} {record.get('Family', '')}", "fr", "flame") else 2,
        "chemical_resistance": scores["dry"].get("chemical_resistance", 5),
        "uv_resistance": scores["dry"].get("uv_resistance", 5),
        "creep_resistance": scores["dry"].get("creep_resistance", 5),
        "tensile_mpa": clean(record.get("Tensile strength")),
        "modulus_gpa": clean(record.get("Tensile modulus")),
        "impact_note": "Approximate catalog orientation; confirm exact impact test from spool TDS.",
        "shrinkage_note": "Grade and print-profile dependent; confirm with the exact product.",
        "scores": scores,
    }
    real = {
        "density_g_cm3": real_property(record.get("Density", ""), "g/cm3"),
        "hdt_c": real_property(record.get("HDT", ""), "C"),
        "continuous_service_c": real_property(record.get("Continuous service temp", ""), "C"),
        "tensile_mpa": real_property(record.get("Tensile strength", ""), "MPa"),
        "modulus_gpa": real_property(record.get("Tensile modulus", ""), "GPa", modulus_midpoint(record.get("Tensile modulus"))),
        "moisture_sensitivity": {"value": props["moisture_sensitivity"], "label": f"{props['moisture_sensitivity']}/10 orientation", "unit": "/10"},
        "price_per_kg": {"value": None, "min": None, "max": None, "label": "", "unit": "EUR/kg"},
    }
    return {
        "id": f"catalog:{slug}",
        "slug": slug,
        "name": name,
        "full_name": clean(record.get("Full name")) or name,
        "family": clean(record.get("Family")) or "Catalog",
        "subfamily": subfamily(record),
        "family_color": family_color(record),
        "formula": "Catalog reference",
        "repeat_unit": aliases or "See exact resin chemistry / spool TDS",
        "description": f"Read-only catalog reference with approximate family-level FFF/FDM ranges.{(' Aliases: ' + aliases) if aliases else ''}",
        "best_for": clean(record.get("Best for")) or "Screening candidate; verify exact product data before use.",
        "avoid_for": clean(record.get("Avoid for")) or "Final engineering decisions without exact spool/TDS confirmation.",
        "settings": settings,
        "properties": props,
        "real_properties": real,
        "scores": scores,
        "compatibility": compatibility(record, printers),
        "source_notes": source_notes,
        "source_title": source_title,
        "source_url": source_url,
        "aliases": aliases,
        "record_kind": clean(record.get("Record kind")),
        "status": "Approximate catalog data",
        "filter_keys": category_filter_keys(record),
        "product_count": 0,
        "products": [],
        "is_catalog": True,
        "search": " ".join(clean(record.get(key)) for key in record),
    }


def catalog_entries(
    existing_slugs: Iterable[str] = (),
    printers: Iterable[Any] | None = None,
    include_existing: bool = False,
) -> list[dict[str, Any]]:
    existing = set(existing_slugs)
    entries = []
    seen = set()
    for record in CATALOG_RECORDS:
        payload = catalog_payload(record, printers)
        if payload["slug"] in seen:
            continue
        seen.add(payload["slug"])
        if not include_existing and payload["slug"] in existing:
            continue
        entries.append(payload)
    return sorted(entries, key=lambda item: (item["family"], item["name"]))


def catalog_entry_by_slug(slug: str, printers: Iterable[Any] | None = None) -> dict[str, Any] | None:
    wanted = slugify(slug)
    for record in CATALOG_RECORDS:
        if slugify(record.get("Material", "")) == wanted:
            return catalog_payload(record, printers)
    return None
